CREATE DEFINER=`root`@`localhost` PROCEDURE `insertAccumulatedAmount` (IN `p_user_id` VARCHAR(15), IN `p_pos_id` INT(11), IN `p_payment_date` DATE)   BEGIN
    INSERT INTO accumulated_amount_tbl (
        user_id,
        pos_id,
        payment_date,
        begin_or_no,
        end_or_no,
        no_of_transaction,
        no_of_void,
	total_sales,
        discount,
        vatable,
        vat_exempt,
        vat,
        zero_rated,
        z_counter,
