CREATE DEFINER=`root`@`localhost` PROCEDURE `saveEjournal` (IN `p_payment_date` DATE, IN `p_pos_id` INT, IN `p_text` LONGBLOB)   BEGIN
    IF EXISTS(SELECT 1 FROM textfile_tbl 
              WHERE payment_date = p_payment_date 
                AND pos_id = p_pos_id) THEN

        DELETE FROM textfile_tbl 
        WHERE payment_date = p_payment_date 
          AND pos_id = p_pos_id;

    END IF;

    INSERT INTO textfile_tbl(payment_date, text_file, pos_id)
    VALUES(p_payment_date, AES_ENCRYPT(p_text, 'strdjnltmyp'), p_pos_id);

END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_getZReadingSummary` (IN `p_pos_id` INT, IN `p_payment_date` DATE)   BEGIN
    SELECT 
        MIN(begin_or_no) AS begin_or_no,
        MAX(end_or_no) AS end_or_no,

        (SELECT IFNULL(MAX(NULLIF(end_balance, 0)), 0)
         FROM accumulated_amount_tbl 
         WHERE payment_date < p_payment_date
         AND pos_id = p_pos_id) AS begin_balance,

        ((SELECT SUM(total_sales) 
          FROM accumulated_amount_tbl 
          WHERE pos_id = p_pos_id 
          AND payment_date = p_payment_date)
        +
        (SELECT IFNULL(MAX(NULLIF(end_balance, 0)), 0)
         FROM accumulated_amount_tbl 
         WHERE payment_date < p_payment_date
           AND pos_id = p_pos_id)) AS end_balance,

        SUM(no_of_transaction) AS no_of_transaction,
        SUM(total_sales) AS total_sales,
        SUM(discount) AS discount,
        SUM(vatable) AS vatable_sale,
        SUM(vat) AS vat,
        SUM(vat_exempt) AS vat_exempt,
        SUM(zero_rated) AS zero_rated_sale,
        MAX(z_counter) AS z_counter,
        SUM(no_of_void) AS no_of_void,
        IFNULL(MIN(NULLIF(begin_void_no, 0)),0) AS begin_void_no,
        MAX(end_void_no) AS end_void_no,
        SUM(void_amount) AS void_amount,
        SUM(grand_total) AS grand_total
    FROM accumulated_amount_tbl
    WHERE pos_id = p_pos_id
      AND payment_date = p_payment_date;

END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `updateAccumulatedAmount` (IN `p_user_id` VARCHAR(15), IN `p_payment_date` DATE, IN `p_pos_id` INT(11), IN `p_end_or_no` VARCHAR(25))   BEGIN
    DECLARE v_no_trx      INT DEFAULT 0;
    DECLARE v_total_sales DECIMAL(25,2) DEFAULT 0;
    DECLARE v_discount    DECIMAL(25,2) DEFAULT 0;
    DECLARE v_vatable     DECIMAL(25,2) DEFAULT 0;
    DECLARE v_vat_exempt  DECIMAL(25,2) DEFAULT 0;
    DECLARE v_vat         DECIMAL(25,2) DEFAULT 0;
    DECLARE v_zero_rated  DECIMAL(25,2) DEFAULT 0;
    DECLARE v_void_sales  DECIMAL(25,2) DEFAULT 0;
    DECLARE v_grand_total DECIMAL(25,2) DEFAULT 0;

    /* Get all totals from or_tbl in one scan */
    SELECT
        COUNT(or_no),
        IFNULL(SUM(CASE WHEN void_status = 'no'
                        THEN vatable + vat_exempt + zero_rated + vat + total_amount
                   END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN discount    END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN vatable     END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN vat_exempt  END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN vat         END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN zero_rated  END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'yes'
                        THEN vatable + vat_exempt + zero_rated + vat + total_amount
                   END), 0)
    INTO
        v_no_trx,
        v_total_sales,
        v_discount,
        v_vatable,
        v_vat_exempt,
        v_vat,
        v_zero_rated,
        v_void_sales
    FROM or_tbl
    WHERE cashier_id = p_user_id
      AND payment_date = p_payment_date;

    SET v_grand_total = v_total_sales - v_void_sales;

    /* Update accumulated_amount_tbl */
    UPDATE accumulated_amount_tbl
    SET pos_id           = p_pos_id,
        end_or_no        = p_end_or_no,
        no_of_transaction = v_no_trx,
        total_sales            = v_total_sales,
        discount         = v_discount,
        vatable          = v_vatable,
        vat_exempt       = v_vat_exempt,
        vat              = v_vat,
        zero_rated       = v_zero_rated,
        grand_total      = v_grand_total,
        updated          = 'yes'
    WHERE user_id     = p_user_id
      AND payment_date = p_payment_date;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `updateZReading` (IN `p_payment_date` DATE, IN `p_pos_id` INT, OUT `p_new_zcounter` INT, OUT `p_prev_grand_total` DECIMAL(18,2))   BEGIN
    DECLARE v_zcounter INT DEFAULT 0;
    DECLARE v_prev_date DATE;

    -- Compute previous date
    SET v_prev_date = DATE_SUB(p_payment_date, INTERVAL 1 DAY);

    -- Get previous day's grand_total
    SELECT IFNULL(MAX(grand_total), 0)
    INTO p_prev_grand_total
    FROM accumulated_amount_tbl
    WHERE payment_date = v_prev_date
      AND pos_id = p_pos_id;

    -- Check if current date record exists
    SELECT z_counter INTO v_zcounter
    FROM accumulated_amount_tbl
    WHERE payment_date = p_payment_date
      AND pos_id = p_pos_id
    LIMIT 1;

    IF v_zcounter IS NULL THEN
        SET p_new_zcounter = -1; -- NO RECORD FOUND
    ELSE
        SET p_new_zcounter = v_zcounter + 1;

        UPDATE accumulated_amount_tbl
        SET 
            z_counter = p_new_zcounter,
            printed = 'yes',
            updated = 'yes'
        WHERE payment_date = p_payment_date
          AND pos_id = p_pos_id;
    END IF;

END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `upsertAccumulatedAmount` (IN `p_user_id` VARCHAR(15), IN `p_payment_date` DATE, IN `p_pos_id` INT(11), IN `p_end_or_no` VARCHAR(25))   BEGIN
    DECLARE v_exists      INT DEFAULT 0;
    DECLARE v_no_trx      INT DEFAULT 0;
    DECLARE v_total_sales DECIMAL(25,2) DEFAULT 0;
    DECLARE v_discount    DECIMAL(25,2) DEFAULT 0;
    DECLARE v_vatable     DECIMAL(25,2) DEFAULT 0;
    DECLARE v_vat_exempt  DECIMAL(25,2) DEFAULT 0;
    DECLARE v_vat         DECIMAL(25,2) DEFAULT 0;
    DECLARE v_zero_rated  DECIMAL(25,2) DEFAULT 0;
    DECLARE v_void_sales  DECIMAL(25,2) DEFAULT 0;
    DECLARE v_grand_total DECIMAL(25,2) DEFAULT 0;

    /* Check if accumulated row already exists */
    SELECT COUNT(*)
    INTO v_exists
    FROM accumulated_amount_tbl
    WHERE user_id = p_user_id
      AND payment_date = p_payment_date;

    /* Get totals from or_tbl in one scan */
    SELECT
        COUNT(or_no),
        IFNULL(SUM(CASE WHEN void_status = 'no'
                        THEN (vatable + vat + vat_exempt + zero_rated)-discount
                   END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN discount    END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN vatable     END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN vat_exempt  END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN vat         END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'no' THEN zero_rated  END), 0),
        IFNULL(SUM(CASE WHEN void_status = 'yes'
                        THEN vatable + vat + vat_exempt + zero_rated
                   END), 0)
    INTO
        v_no_trx,
        v_total_sales,
        v_discount,
        v_vatable,
        v_vat_exempt,
        v_vat,
        v_zero_rated,
        v_void_sales
    FROM or_tbl
    WHERE cashier_id = p_user_id
      AND payment_date = p_payment_date;

    SET v_grand_total = v_total_sales - v_void_sales;

    /* If exists → UPDATE, else → INSERT */
    IF v_exists > 0 THEN
        UPDATE accumulated_amount_tbl
        SET pos_id            = p_pos_id,
            end_or_no         = p_end_or_no,
            no_of_transaction = v_no_trx,
            no_of_void        = 0,
            total_sales       = v_total_sales,
            discount          = v_discount,
            vatable           = v_vatable,
            vat_exempt        = v_vat_exempt,
            vat               = v_vat,
            zero_rated        = v_zero_rated,
            grand_total       = v_grand_total,
            updated           = 'yes'
        WHERE user_id      = p_user_id
          AND payment_date = p_payment_date;
    ELSE
        INSERT INTO accumulated_amount_tbl (
            user_id,
            pos_id,
            payment_date,
            begin_or_no,
            end_or_no,
            no_of_transaction,
            no_of_void,
            total_sales,
            discount,
            vatable,
            vat_exempt,
            vat,
            zero_rated,
            z_counter,
            begin_void_no,
            end_void_no,
            void_amount,
            grand_total,
            printed,
            upload,
            updated
        )
        SELECT
            p_user_id,
            p_pos_id,
            p_payment_date,
            MIN(or_no),
            MAX(or_no),
            v_no_trx,
            0,
            v_total_sales,
            v_discount,
            v_vatable,
            v_vat_exempt,
            v_vat,
            v_zero_rated,
            0,
            0,
            0,
            '0.00',
            v_grand_total,
            'no',
            'no',
            'yes'
        FROM or_tbl
        WHERE cashier_id = p_user_id
          AND payment_date = p_payment_date;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `voidTransaction` (IN `p_or_no` VARCHAR(25), IN `p_pos_id` INT(11), IN `p_payment_date` DATE, IN `p_void_no` VARCHAR(25), IN `p_manager_id` VARCHAR(50), IN `p_cashier_id` VARCHAR(15), OUT `p_result` INT, OUT `p_message` VARCHAR(255))   BEGIN
    DECLARE v_exists      INT DEFAULT 0;
    DECLARE v_total_sales DECIMAL(25,2);
    DECLARE v_vatable     DECIMAL(25,2);
    DECLARE v_vat_exempt  DECIMAL(25,2);
    DECLARE v_zero_rated  DECIMAL(25,2);
    DECLARE v_vat         DECIMAL(25,2);
    DECLARE v_discount    DECIMAL(25,2);
    DECLARE v_void_total  DECIMAL(25,2);

   -- add these two variables:
    DECLARE v_sqlstate CHAR(5);
    DECLARE v_errmsg   TEXT;

    -- error handler
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
       GET DIAGNOSTICS CONDITION 1
            v_sqlstate = RETURNED_SQLSTATE,
            v_errmsg   = MESSAGE_TEXT;

        ROLLBACK;
        SET p_result  = -1;
	SET p_message = CONCAT('SQLSTATE ', v_sqlstate, ': ', v_errmsg);
        /* SET p_message = 'Database error while voiding transaction'; */
    END;

    START TRANSACTION;

    -- check if OR exists and not yet voided
    SELECT COUNT(*)
    INTO v_exists
    FROM or_tbl
    WHERE or_no        = p_or_no
      AND void_status  = 'no'
      AND payment_date = p_payment_date
      AND pos_id       = p_pos_id
    FOR UPDATE;

    IF v_exists = 0 THEN
        -- already voided or not found
        ROLLBACK;
        SET p_result  = 0;
        SET p_message = 'Ticket is already voided or expired';
    ELSE
       /*--------------------------------------------------------------*/
        -- 2) Update OR (negative amounts, mark void)
       /*--------------------------------------------------------------*/
        UPDATE or_tbl
        SET base_price   = base_price   * -1,
            total_amount = total_amount * -1,
            qty          = qty          * -1,
            vatable      = vatable      * -1,
            vat_exempt   = vat_exempt   * -1,
            zero_rated   = zero_rated   * -1,
            vat          = vat          * -1,
            discount     = discount     * -1,
            void_by      = p_manager_id,
            void_status  = 'yes',
            updated      = 'yes'
        WHERE or_no = p_or_no
          AND pos_id = p_pos_id;

       /*--------------------------------------------------------------*/
        -- 3) Update e_journal_tbl
       /*--------------------------------------------------------------*/
        UPDATE e_journal_tbl
        SET qty           = qty           * -1,
            base_price    = base_price    * -1, 
            total_amount  = total_amount  * -1,
            cash_tendered = cash_tendered * -1,
            change_amount = change_amount * -1,
            discount      = discount      * -1,
            vatable       = vatable       * -1,
            vat_exempt    = vat_exempt    * -1,
            zero_rated    = zero_rated    * -1,
            vat           = vat           * -1,
            void_status   = 'yes',
            updated       = 'yes'
        WHERE or_no = p_or_no
          AND pos_id = p_pos_id;

       /*--------------------------------------------------------------*/
        -- 4) Update or_items_tbl
       /*--------------------------------------------------------------*/
        UPDATE or_items_tbl
        SET qty           	= qty           * -1,
            base_price    	= base_price    * -1, 
            total_amount  	= total_amount  * -1,
            discount	   	= discount      * -1,
            vatable       	= vatable       * -1,
            vat_exempt    	= vat_exempt    * -1,
            zero_rated    	= zero_rated    * -1,
            vat           	= vat           * -1,
            void_status  	= 'yes',
            updated       	= 'yes'
        WHERE or_no = p_or_no
          AND pos_no = p_pos_id;

       /*--------------------------------------------------------------*/
        -- 5) Insert into void_tbl (copy from or_tbl)
       /*--------------------------------------------------------------*/
        INSERT INTO void_tbl
        (
            void_no, or_no, payment_date, payment_time, pos_id, qty, user_id,
            base_price, vatable, vat_exempt, zero_rated, vat, discount,
            total_amount, void_type, void_by, upload
        )
        SELECT
            p_void_no, or_no, payment_date, payment_time, pos_id, qty, p_cashier_id,
            base_price, vatable, vat_exempt, zero_rated, vat, discount,
            total_amount, 'Ticket Sale', p_manager_id, 'no'
        FROM or_tbl
        WHERE or_no = p_or_no
          AND pos_id = p_pos_id;

       /*--------------------------------------------------------------*/
        -- 6) Insert into audit_trail_tbl
       /*--------------------------------------------------------------*/
        INSERT INTO audit_trail_tbl
        (
            pos_id, or_no, date, time,
            cashier, manager, activity_performed,
            vatable, vat, vat_exempt, zero_rated, discount,
            total_amount, upload
        )
        SELECT
            p_pos_id,
            or_no,
            CURDATE(),
            CURTIME(),
            p_cashier_id,
            p_manager_id,
            'Void Transaction',
            vatable, vat, vat_exempt, zero_rated, discount,
            total_amount,
            'no'
        FROM or_tbl
        WHERE or_no = p_or_no
          AND pos_id = p_pos_id;

       /*--------------------------------------------------------------*/
        -- 7) Recompute totals for accumulated_amount_tbl
       /*--------------------------------------------------------------*/
        SELECT
            -- total_sales
            IFNULL((
                SELECT SUM(total_amount)
                FROM void_tbl
                WHERE or_no = p_or_no
                  AND pos_id = p_pos_id
            ),0)
            +
            IFNULL((
                SELECT grand_total
                FROM accumulated_amount_tbl
                WHERE user_id = p_cashier_id
                  AND payment_date = p_payment_date
                  AND pos_id = p_pos_id
            ),0),
            -- vatable
            IFNULL((
                SELECT vatable
                FROM void_tbl
                WHERE or_no = p_or_no
                  AND pos_id = p_pos_id
                LIMIT 1
            ),0)
            +
            IFNULL((
                SELECT vatable
                FROM accumulated_amount_tbl
                WHERE user_id = p_cashier_id
                  AND payment_date = p_payment_date
                  AND pos_id = p_pos_id
            ),0),
            -- vat_exempt
            IFNULL((
                SELECT vat_exempt
                FROM void_tbl
                WHERE or_no = p_or_no
                  AND pos_id = p_pos_id
                LIMIT 1
            ),0)
            +
            IFNULL((
                SELECT vat_exempt
                FROM accumulated_amount_tbl
                WHERE user_id = p_cashier_id
                  AND payment_date = p_payment_date
                  AND pos_id = p_pos_id
            ),0),
            -- zero_rated
            IFNULL((
                SELECT zero_rated
                FROM void_tbl
                WHERE or_no = p_or_no
                  AND pos_id = p_pos_id
                LIMIT 1
            ),0)
            +
            IFNULL((
                SELECT zero_rated
                FROM accumulated_amount_tbl
                WHERE user_id = p_cashier_id
                  AND payment_date = p_payment_date
                  AND pos_id = p_pos_id
            ),0),
            -- vat
            IFNULL((
                SELECT vat
                FROM void_tbl
                WHERE or_no = p_or_no
                  AND pos_id = p_pos_id
                LIMIT 1
            ),0)
            +
            IFNULL((
                SELECT vat
                FROM accumulated_amount_tbl
                WHERE user_id = p_cashier_id
                  AND payment_date = p_payment_date
                  AND pos_id = p_pos_id
            ),0),
            -- discount
            IFNULL((
                SELECT discount
                FROM void_tbl
                WHERE or_no = p_or_no
                  AND pos_id = p_pos_id
                LIMIT 1
            ),0)
            +
            IFNULL((
                SELECT discount
                FROM accumulated_amount_tbl
                WHERE user_id = p_cashier_id
                  AND payment_date = p_payment_date
                  AND pos_id = p_pos_id
            ),0),
            -- void_total
            IFNULL((
                SELECT SUM(total_amount)
                FROM void_tbl
                WHERE or_no = p_or_no
                  AND pos_id = p_pos_id
            ),0)
            +
            IFNULL((
                SELECT void_amount
                FROM accumulated_amount_tbl
                WHERE user_id = p_cashier_id
                  AND payment_date = p_payment_date
                  AND pos_id = p_pos_id
            ),0)
        INTO
            v_total_sales, v_vatable, v_vat_exempt, v_zero_rated,
            v_vat, v_discount, v_void_total;

        UPDATE accumulated_amount_tbl
        SET no_of_void   = (SELECT COUNT(*)
                            FROM void_tbl
                            WHERE user_id = p_cashier_id
                              AND payment_date = p_payment_date
                              AND pos_id = p_pos_id),
            begin_void_no = (SELECT MIN(void_no)
                             FROM void_tbl
                             WHERE user_id = p_cashier_id
                               AND payment_date = p_payment_date
                               AND pos_id = p_pos_id),
            end_void_no   = (SELECT MAX(void_no)
                             FROM void_tbl
                             WHERE user_id = p_cashier_id
                               AND payment_date = p_payment_date
                               AND pos_id = p_pos_id),
            void_amount   = v_void_total,
            grand_total   = v_total_sales,
            vatable       = v_vatable,
            vat_exempt    = v_vat_exempt,
            zero_rated    = v_zero_rated,
            vat           = v_vat,
            discount      = v_discount,
            updated       = 'yes'
        WHERE user_id      = p_cashier_id
          AND payment_date = p_payment_date
          AND pos_id       = p_pos_id;

        COMMIT;
        SET p_result  = 1;
        SET p_message = 'Transaction voided successfully';
    END IF;

END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `void_item` (IN `p_void_no` VARCHAR(25), IN `p_or_no` VARCHAR(25), IN `p_pos_id` INT(11), IN `p_ride_type` VARCHAR(255), IN `p_qty` INT(11), IN `p_user_id` VARCHAR(15), IN `p_base_price` DECIMAL(25,2), IN `p_vatable` DECIMAL(25,2), IN `p_vat_exempt` DECIMAL(25,2), IN `p_zero_rated` DECIMAL(25,2), IN `p_vat` DECIMAL(25,2), IN `p_discount` DECIMAL(25,2), IN `p_total_amount` DECIMAL(25,2), IN `p_void_type` VARCHAR(100), IN `p_void_by` VARCHAR(15), IN `p_upload` VARCHAR(3), OUT `p_message` VARCHAR(255))   BEGIN
    IF p_or_no IS NULL OR p_or_no = 0 THEN
        SET p_message = 'Item Invalid.';
    ELSE
        INSERT INTO void_item_tbl(void_no, or_no, transaction_date, transaction_time, pos_id, ride_type, qty, user_id, base_price, vatable, vat_exempt, zero_rated, vat, discount, total_amount, void_type, void_by, upload)
        VALUES ( p_void_no, p_or_no, CURDATE(), CURTIME(), p_pos_id, p_ride_type, p_qty, p_user_id, p_base_price, p_vatable, p_vat_exempt, p_zero_rated, p_vat, p_discount, p_total_amount, p_void_type, p_void_by, p_upload);

        SET p_message = 'Saved successfully.';
    END IF;
END$$

